#[test]
fn test_burst_capacity_exhausted() {
    let mut bucket = TokenBucket::new(5, 1.0);
    for _ in 0..5 {
        assert!(bucket.try_acquire());
    }
    assert!(!bucket.try_acquire());
}

#[test]
fn test_acquire_many_within_capacity() {
    let mut bucket = TokenBucket::new(10, 1.0);
    assert!(bucket.try_acquire_many(5));
    assert!(bucket.try_acquire_many(5));
    assert!(!bucket.try_acquire());
}

#[test]
fn test_acquire_many_exceeds_capacity() {
    let mut bucket = TokenBucket::new(5, 1.0);
    assert!(!bucket.try_acquire_many(6));
    assert_eq!(bucket.available(), 5.0); // Unchanged
}
\`\`\`

6. **Refill Tests**
\`\`\`rust
#[test]
fn test_refill_rate() {
    let mut bucket = TokenBucket::new(10, 100.0); // 100/sec
    for _ in 0..10 {
        bucket.try_acquire();
    }

    std::thread::sleep(Duration::from_millis(55));
    let available = bucket.available();
    assert!(available >= 4.5 && available <= 6.0);
}

#[test]
fn test_refill_capped_at_capacity() {
    let mut bucket = TokenBucket::new(5, 100.0);
    std::thread::sleep(Duration::from_millis(100));
    assert_eq!(bucket.available(), 5.0);
}

#[test]
fn test_fractional_tokens() {
    let mut bucket = TokenBucket::new(10, 10.0); // 10/sec
    bucket.try_acquire_many(10);

    std::thread::sleep(Duration::from_millis(50)); // 0.5 tokens
    assert!(!bucket.check()); // Need 1.0

    std::thread::sleep(Duration::from_millis(55)); // 0.5 more
    assert!(bucket.check()); // Now have >= 1.0
}
