Add robust connection retry logic to handle USB flakiness and disconnections.

## Implementation

### ConnectionOptions Struct
```rust
// src/device.rs
use std::time::Duration;

#[derive(Debug, Clone)]
pub struct ConnectionOptions {
    /// Maximum number of connection attempts (default: 3)
    pub max_retries: u32,
    /// Initial delay between retries (default: 1000ms)
    pub retry_delay: Duration,
    /// Exponential backoff factor (default: 1.5)
    pub backoff_factor: f32,
    /// Maximum delay cap (default: 10000ms)
    pub max_delay: Duration,
}

impl Default for ConnectionOptions {
    fn default() -> Self {
        Self {
            max_retries: 3,
            retry_delay: Duration::from_millis(1000),
            backoff_factor: 1.5,
            max_delay: Duration::from_millis(10000),
        }
    }
}
```

### open_with_retry Method
```rust
impl Device {
    #[instrument(skip(self), fields(serial = ?serial, max_retries = %opts.max_retries))]
    pub fn open_with_retry(
        serial: Option<&str>,
        opts: &ConnectionOptions,
    ) -> Result<Self, DeviceError> {
        let mut delay = opts.retry_delay;

        for attempt in 1..=opts.max_retries {
            let span = span!(Level::DEBUG, "connection_attempt", attempt = %attempt);
            let _enter = span.enter();

            match Self::open(serial) {
                Ok(device) => {
                    info!(attempt = %attempt, "Device connected successfully");
                    return Ok(device);
                }
                Err(e) if e.is_connection_error() && attempt < opts.max_retries => {
                    warn!(
                        attempt = %attempt,
                        max = %opts.max_retries,
                        error = %e,
                        delay_ms = %delay.as_millis(),
                        "Connection failed, retrying"
                    );
                    std::thread::sleep(delay);
                    delay = Duration::from_secs_f32(
                        (delay.as_secs_f32() * opts.backoff_factor)
                            .min(opts.max_delay.as_secs_f32())
                    );
                }
                Err(e) => {
                    error!(
                        attempt = %attempt,
                        error = %e,
                        "Connection failed, no more retries"
                    );
                    return Err(e);
                }
            }
        }
        unreachable!()
    }
}
```

## Edge Cases
- First attempt succeeds immediately (common case)
- All retries exhausted → return final error with context
- Non-connection errors (permission, etc.) → fail fast, no retry
- Ctrl+C during sleep → propagate interrupt

## Logging Requirements
- TRACE: Entry/exit of retry loop iterations
- DEBUG: Connection attempt start, delay calculation
- INFO: Successful connection (with attempt count)
- WARN: Failed attempt with retry pending
- ERROR: Final failure after all retries exhausted

## Success Criteria
- [ ] Retries up to configured max
- [ ] Exponential backoff applied correctly
- [ ] Delay capped at max_delay
- [ ] Connection errors trigger retry, others fail fast
- [ ] Robot mode emits retry events as JSON","status":"open","priority":0,"issue_type":"task","created_at":"2026-01-19T18:24:24.758006167Z","created_by":"ubuntu","updated_at":"2026-01-19T21:08:00.994099011Z","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-1os","depends_on_id":"bd-ylj","type":"parent-child","created_at":"2026-01-19T18:24:24.774281400Z","created_by":"ubuntu"}]}
