use std::sync::Mutex;
use once_cell::sync::Lazy;

static SESSION_STATE: Lazy<Mutex<SessionState>> = Lazy::new(|| {
    Mutex::new(SessionState::default())
});

#[derive(Default)]
pub struct SessionState {
    pub brightness: Option<u8>,
    pub keys: HashMap<u8, KeyState>,
}

pub enum KeyState {
    Image(PathBuf),
    Color(String),
    Cleared,
}

impl SessionState {
    pub fn record_brightness(&mut self, level: u8) {
        self.brightness = Some(level);
    }

    pub fn record_set_key(&mut self, key: u8, path: PathBuf) {
        self.keys.insert(key, KeyState::Image(path));
    }

    pub fn record_fill_key(&mut self, key: u8, color: String) {
        self.keys.insert(key, KeyState::Color(color));
    }

    pub fn record_clear_key(&mut self, key: u8) {
        self.keys.insert(key, KeyState::Cleared);
    }
}

// Call from command handlers
pub fn track_brightness(level: u8) {
    SESSION_STATE.lock().unwrap().record_brightness(level);
}
