### Phase 2: Export Command
```rust
// In src/cli/mod.rs
ExportScript {
    /// Embed images as base64 (makes script self-contained)
    #[arg(long)]
    embed_images: bool,

    /// Export from saved profile instead of session
    #[arg(long)]
    profile: Option<String>,

    /// Output format
    #[arg(long, default_value = "bash")]
    format: ExportFormat,
}

#[derive(ValueEnum, Clone)]
enum ExportFormat {
    Bash,
    Fish,
    PowerShell,
    Makefile,
}

// In main.rs
fn cmd_export_script(opts: ExportOptions) -> Result<()> {
    let state = if let Some(profile) = &opts.profile {
        load_profile_state(profile)?
    } else {
        SESSION_STATE.lock().unwrap().clone()
    };

    let script = generate_script(&state, &opts)?;
    println!("{}", script);
    Ok(())
}

fn generate_script(state: &SessionState, opts: &ExportOptions) -> String {
    let mut lines = vec![
        "#!/bin/bash".to_string(),
        format!("# Stream Deck configuration exported by sd"),
        format!("# Exported: {}", chrono::Utc::now().to_rfc3339()),
        "".to_string(),
        "set -e".to_string(),
        "".to_string(),
    ];

    if let Some(brightness) = state.brightness {
        lines.push(format!("sd brightness {}", brightness));
    }

    for (key, key_state) in &state.keys {
        match key_state {
            KeyState::Image(path) => {
                if opts.embed_images {
                    let b64 = base64_encode_image(path)?;
                    lines.push(format!(
                        "echo \"{}\" | base64 -d | sd set-key {} -",
                        b64, key
                    ));
                } else {
                    lines.push(format!("sd set-key {} \"{}\"", key, path.display()));
                }
            }
            KeyState::Color(color) => {
                lines.push(format!("sd fill-key {} \"{}\"", key, color));
            }
            KeyState::Cleared => {
                lines.push(format!("sd clear-key {}", key));
            }
        }
    }

    lines.push("".to_string());
    lines.push("echo \"Configuration applied successfully\"".to_string());

    lines.join("\n")
}
```

## Key Design Decisions
1. **Shell script default**: Most portable, universally understood
2. **Absolute paths**: Avoid relative path confusion
3. **Embed option**: Self-contained scripts for sharing
4. **Multiple formats**: Bash, Fish, PowerShell for cross-platform
5. **set -e**: Fail fast on errors

